    while (low <= high) {
        // Partition in the first array
        int partition1 = (low + high) / 2;
        // Partition in the second array
        int partition2 = (m + n + 1) / 2 - partition1;
        int maxLeft1 = (partition1 == 0) ? Integer.MIN_VALUE : nums1[partition1 - 1];
