    // If the value doesn't exist
    if (temp.data != value) {
        return false;
    }
    // No children
    if (temp.right == null && temp.left == null) {
        if (temp == root) {
            root = null;
        } else // This if/else assigns the new node to be either the left or right child of the
        // parent
        if (temp.parent.data < temp.data) {
            temp.parent.right = null;
        } else {
            temp.parent.left = null;
        }
        return true;
    } else // Two children
    if (temp.left != null && temp.right != null) {
        Node successor = findSuccessor(temp);
        // The left tree of temp is made the left tree of the successor
        successor.left = temp.left;
        successor.left.parent = successor;
        // If the successor has a right child, the child's grandparent is it's new parent
        if (successor.parent != temp) {
            if (successor.right != null) {
                successor.right.parent = successor.parent;
                successor.parent.left = successor.right;
            } else {
                successor.parent.left = null;
            }
            successor.right = temp.right;
            successor.right.parent = successor;
        }
        if (temp == root) {
            successor.parent = null;
            root = successor;
        } else // If you're not deleting the root
        {
            successor.parent = temp.parent;
            // This if/else assigns the new node to be either the left or right child of the
            // parent
            if (temp.parent.data < temp.data) {
                temp.parent.right = successor;
            } else {
                temp.parent.left = successor;
            }
        }
        return true;
    } else // One child
    {
        // If it has a right child
        if (temp.right != null) {
            if (temp == root) {
                root = temp.right;
                return true;
            }
            temp.right.parent = temp.parent;
            // Assigns temp to left or right child
            if (temp.data < temp.parent.data) {
                temp.parent.left = temp.right;
            } else {
                temp.parent.right = temp.right;
            }
        } else // If it has a left child
        {
            if (temp == root) {
                root = temp.left;
                return true;
            }
            temp.left.parent = temp.parent;
            // Assigns temp to left or right side
            if (temp.data < temp.parent.data) {
                temp.parent.left = temp.left;
            } else {
                temp.parent.right = temp.left;
            }
        }
        return true;
    }
}

