        carry = carry(a.charAt(i), b.charAt(i), carry);
        result.append(sum);
    }
    // If there's a remaining carry, append it
    if (carry == '1') {
        result.append('1');
    }
    // Reverse the result as we constructed it from the least significant bit
    return result.reverse().toString();
}

