        for (int j = 0; j < num; j++) {
            if (magicSquare[i][j] < 10) {
                System.out.print(" ");
            }
            if (magicSquare[i][j] < 100) {
                System.out.print(" ");
            }
            System.out.print(magicSquare[i][j] + " ");
        }
        System.out.println();
    }
